
-- Create dms_document_types table
CREATE TABLE public.dms_document_types (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  code TEXT NOT NULL,
  document_name TEXT NOT NULL,
  document_description TEXT,
  tier TEXT,
  rlmu TEXT,
  discipline_code TEXT,
  discipline_name TEXT,
  acceptable_status TEXT,
  is_active BOOLEAN NOT NULL DEFAULT true,
  display_order INTEGER NOT NULL DEFAULT 0,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.dms_document_types ENABLE ROW LEVEL SECURITY;

-- RLS policies
CREATE POLICY "Authenticated users can view document types"
  ON public.dms_document_types FOR SELECT TO authenticated USING (true);

CREATE POLICY "Authenticated users can insert document types"
  ON public.dms_document_types FOR INSERT TO authenticated WITH CHECK (true);

CREATE POLICY "Authenticated users can update document types"
  ON public.dms_document_types FOR UPDATE TO authenticated USING (true) WITH CHECK (true);

CREATE POLICY "Authenticated users can delete document types"
  ON public.dms_document_types FOR DELETE TO authenticated USING (true);

